}

int loadData(char *filename, Record *records, LatLong *locations, int maxRecords){
    FILE   *flist,*fp;
	int    i=0;
	char dbname[64];
	int recNum=0;



    flist = fopen(filename, "r");
	if (!flist) {
        fprintf(stderr, "error opening filelist\n");
        exit(0);
    }

	while(!feof(flist) && recNum < maxRecords) {





		if(fscanf(flist, "%s\n", dbname) != 1) {
            if (!feof(flist)) {
                fprintf(stderr, "error reading filelist\n");
            }
            break;
        }
        fp = fopen(dbname, "r");
        if(!fp) {
            printf("error opening a db\n");
            exit(1);
        }

        while(!feof(fp) && recNum < maxRecords){
            Record *record = &records[recNum];
            LatLong *latLong = &locations[recNum];
            if (fgets(record->recString, 49, fp) == NULL) break;
            fgetc(fp); 
            if (feof(fp)) break;


            char substr[6];

            for(i=0;i<5;i++) substr[i] = *(record->recString+i+28);
            substr[5] = '\0';
            latLong->lat = atof(substr);

            for(i=0;i<5;i++) substr[i] = *(record->recString+i+33);
            substr[5] = '\0';
            latLong->lng = atof(substr);

            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);

    return recNum;
}

void findLowest(Record *records, float *distances, int numRecords, int topN){
  int i,j;
  float val;
  int minLoc;
  Record tempRec;
  float tempDist;

  for(i=0;i<topN;i++) {
    minLoc = i;
    for(j=i;j<numRecords;j++) {
      val = distances[j];
      if (val < distances[minLoc]) minLoc = j;
    }

    tempRec = records[i];
    records[i] = records[minLoc];
    records[minLoc] = tempRec;

    tempDist = distances[i];
    distances[i] = distances[minLoc];
    distances[minLoc] = tempDist;


    records[i].distance = distances[i];
  }
}

int parseCommandline(int argc, char *argv[], char* filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d){
    int i;
    if (argc < 2) return 1; 
    strncpy(filename,argv[1],100);
    char flag;

    for(i=1;i<argc;i++) {
      if (argv[i][0]=='-') {
        flag = argv[i][1];
          switch (flag) {
            case 'r': 
              i++;
              if (i < argc) *r = atoi(argv[i]);
              break;
            case 'l': 
              if (argv[i][2]=='a') {
                i++;
                if (i < argc) *lat = atof(argv[i]);
              }
              else {
                i++;
                if (i < argc) *lng = atof(argv[i]);
              }
              break;
            case 'h': 
              return 1;
            case 'q': 
              *q = 1;
              break;
            case 't': 
              *t = 1;
              break;
            case 'p': 
              i++;
              if (i < argc) *p = atoi(argv[i]);
              break;
            case 'd': 
              i++;
              if (i < argc) *d = atoi(argv[i]);
              break;
        }
      }
    }
    if ((*d >= 0 && *p<0) || (*p>=0 && *d<0)) 
      return 1;
    return 0;
}

